*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --bg: #0f0f1a;
  --bg2: #1a1a2e;
  --bg3: #16213e;
  --accent: #7c3aed;
  --accent2: #a855f7;
  --accent-hover: #6d28d9;
  --text: #e2e8f0;
  --text-muted: #94a3b8;
  --border: #2d3748;
  --msg-own: #4c1d95;
  --msg-other: #1e293b;
  --online: #22c55e;
  --danger: #ef4444;
  --radius: 12px;
  --sidebar-w: 260px;
  --online-w: 180px;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  background: var(--bg);
  color: var(--text);
  height: 100vh;
  overflow: hidden;
}

/* ── MODAL ── */
.modal-overlay {
  position: fixed; inset: 0;
  background: rgba(0,0,0,0.7);
  display: flex; align-items: center; justify-content: center;
  z-index: 1000;
  backdrop-filter: blur(4px);
}

.modal {
  background: var(--bg2);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 2rem;
  width: 360px;
  text-align: center;
  box-shadow: 0 20px 60px rgba(0,0,0,0.5);
}

.modal h2 { font-size: 1.5rem; margin-bottom: .5rem; }
.modal p { color: var(--text-muted); margin-bottom: 1.5rem; font-size: .9rem; }

.modal input {
  width: 100%;
  background: var(--bg3);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: .75rem 1rem;
  color: var(--text);
  font-size: 1rem;
  margin-bottom: 1rem;
  outline: none;
  transition: border-color .2s;
}

.modal input:focus { border-color: var(--accent2); }

.modal button {
  width: 100%;
  background: var(--accent);
  color: white;
  border: none;
  border-radius: 8px;
  padding: .75rem;
  font-size: 1rem;
  cursor: pointer;
  transition: background .2s;
  font-weight: 600;
}

.modal button:hover { background: var(--accent-hover); }

/* ── LAYOUT ── */
.hidden { display: none !important; }

#app {
  display: flex;
  height: 100vh;
}

/* ── SIDEBAR ── */
.sidebar {
  width: var(--sidebar-w);
  background: var(--bg2);
  border-right: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  flex-shrink: 0;
}

.sidebar-header {
  padding: 1.25rem 1rem;
  border-bottom: 1px solid var(--border);
}

.sidebar-header h1 {
  font-size: 1.2rem;
  font-weight: 700;
  color: var(--accent2);
}

.my-nickname {
  font-size: .8rem;
  color: var(--text-muted);
  margin-top: .25rem;
  display: block;
}

.sidebar-section {
  flex: 1;
  overflow-y: auto;
  padding: 1rem;
}

.section-title {
  font-size: .75rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: .08em;
  color: var(--text-muted);
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: .75rem;
}

.icon-btn {
  background: var(--accent);
  color: white;
  border: none;
  border-radius: 50%;
  width: 22px; height: 22px;
  font-size: 1.1rem;
  cursor: pointer;
  display: flex; align-items: center; justify-content: center;
  line-height: 1;
  transition: background .2s;
}

.icon-btn:hover { background: var(--accent-hover); }

/* ── ROOM LIST ── */
.room-list { display: flex; flex-direction: column; gap: .35rem; }

.room-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: .6rem .75rem;
  border-radius: 8px;
  cursor: pointer;
  transition: background .15s;
  border: 1px solid transparent;
}

.room-item:hover { background: var(--bg3); }
.room-item.active {
  background: rgba(124,58,237,.2);
  border-color: rgba(124,58,237,.4);
}

.room-item-name {
  font-size: .9rem;
  font-weight: 500;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.room-item-count {
  font-size: .75rem;
  color: var(--text-muted);
  background: var(--bg3);
  border-radius: 10px;
  padding: .1rem .4rem;
  flex-shrink: 0;
  margin-left: .5rem;
}

/* ── CREATE ROOM FORM ── */
.create-room-form {
  padding: .75rem 1rem 1rem;
  border-top: 1px solid var(--border);
}

.create-room-form input {
  width: 100%;
  background: var(--bg3);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: .6rem .75rem;
  color: var(--text);
  font-size: .9rem;
  outline: none;
  margin-bottom: .5rem;
}

.create-room-form input:focus { border-color: var(--accent2); }

.form-actions { display: flex; gap: .5rem; }

.form-actions button {
  flex: 1;
  padding: .5rem;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  font-size: .85rem;
  font-weight: 600;
  transition: background .2s;
}

.form-actions button:first-child {
  background: var(--accent);
  color: white;
}

.form-actions button:first-child:hover { background: var(--accent-hover); }

.btn-secondary {
  background: var(--bg3) !important;
  color: var(--text-muted) !important;
  border: 1px solid var(--border) !important;
}

.btn-secondary:hover { background: var(--border) !important; }

/* ── CHAT AREA ── */
.chat-area {
  flex: 1;
  display: flex;
  overflow: hidden;
  position: relative;
}

.no-room {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  color: var(--text-muted);
  gap: 1rem;
}

.no-room-icon { font-size: 3rem; opacity: .4; }
.no-room p { font-size: 1rem; }

/* ── ROOM VIEW ── */
#room-view {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.chat-header {
  padding: 1rem 1.25rem;
  border-bottom: 1px solid var(--border);
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--bg2);
  flex-shrink: 0;
}

.room-title {
  font-size: 1.1rem;
  font-weight: 700;
}

.chat-header-right {
  display: flex;
  align-items: center;
  gap: .75rem;
}

.online-count {
  font-size: .8rem;
  color: var(--online);
  font-weight: 600;
}

.leave-btn {
  background: transparent;
  color: var(--danger);
  border: 1px solid var(--danger);
  border-radius: 6px;
  padding: .3rem .7rem;
  font-size: .8rem;
  cursor: pointer;
  transition: all .2s;
}

.leave-btn:hover {
  background: var(--danger);
  color: white;
}

/* ── CHAT BODY ── */
.chat-body {
  flex: 1;
  overflow-y: auto;
  padding: 1rem 1.25rem;
  display: flex;
  flex-direction: column;
  gap: .5rem;
  scroll-behavior: smooth;
}

.chat-body::-webkit-scrollbar { width: 6px; }
.chat-body::-webkit-scrollbar-track { background: transparent; }
.chat-body::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }

/* ── MESSAGES ── */
.messages { display: flex; flex-direction: column; gap: .5rem; }

.msg {
  display: flex;
  flex-direction: column;
  max-width: 70%;
}

.msg.own { align-self: flex-end; align-items: flex-end; }
.msg.other { align-self: flex-start; align-items: flex-start; }

.msg-meta {
  font-size: .7rem;
  color: var(--text-muted);
  margin-bottom: .2rem;
  padding: 0 .25rem;
}

.msg-bubble {
  padding: .6rem .9rem;
  border-radius: 16px;
  font-size: .9rem;
  line-height: 1.5;
  word-break: break-word;
  white-space: pre-wrap;
}

.msg.own .msg-bubble {
  background: var(--msg-own);
  border-bottom-right-radius: 4px;
  color: #e9d5ff;
}

.msg.other .msg-bubble {
  background: var(--msg-other);
  border-bottom-left-radius: 4px;
}

.msg-time {
  font-size: .65rem;
  color: var(--text-muted);
  margin-top: .15rem;
  padding: 0 .25rem;
}

/* System messages */
.msg-system {
  align-self: center;
  font-size: .75rem;
  color: var(--text-muted);
  background: rgba(255,255,255,.05);
  padding: .25rem .75rem;
  border-radius: 20px;
  margin: .25rem 0;
}

/* ── TYPING INDICATOR ── */
.typing-indicator {
  font-size: .78rem;
  color: var(--text-muted);
  padding: .25rem 0;
  min-height: 1.5rem;
  display: flex;
  align-items: center;
  gap: .4rem;
}

.typing-dots {
  display: flex; gap: 3px;
}

.typing-dots span {
  width: 5px; height: 5px;
  background: var(--text-muted);
  border-radius: 50%;
  animation: bounce 1.2s infinite;
}

.typing-dots span:nth-child(2) { animation-delay: .2s; }
.typing-dots span:nth-child(3) { animation-delay: .4s; }

@keyframes bounce {
  0%, 60%, 100% { transform: translateY(0); }
  30% { transform: translateY(-5px); }
}

/* ── ONLINE PANEL ── */
.online-panel {
  width: var(--online-w);
  border-left: 1px solid var(--border);
  background: var(--bg2);
  padding: 1rem;
  flex-shrink: 0;
  overflow-y: auto;
}

.online-panel-title {
  font-size: .75rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: .08em;
  color: var(--text-muted);
  margin-bottom: .75rem;
}

.online-users { display: flex; flex-direction: column; gap: .5rem; }

.online-user {
  display: flex;
  align-items: center;
  gap: .5rem;
  font-size: .85rem;
}

.online-dot {
  width: 8px; height: 8px;
  background: var(--online);
  border-radius: 50%;
  flex-shrink: 0;
  box-shadow: 0 0 6px var(--online);
}

.online-user-name {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.online-user-name.is-me { color: var(--accent2); font-weight: 600; }

/* ── INPUT AREA ── */
.input-area {
  padding: 1rem 1.25rem;
  border-top: 1px solid var(--border);
  display: flex;
  gap: .75rem;
  align-items: center;
  background: var(--bg2);
  flex-shrink: 0;
}

.input-area input {
  flex: 1;
  background: var(--bg3);
  border: 1px solid var(--border);
  border-radius: 24px;
  padding: .7rem 1.2rem;
  color: var(--text);
  font-size: .95rem;
  outline: none;
  transition: border-color .2s;
}

