*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --bg: #0f0f1a;
  --bg2: #1a1a2e;
  --bg3: #16213e;
  --accent: #7c3aed;
  --accent2: #a855f7;
  --accent-hover: #6d28d9;
  --text: #e2e8f0;
  --text-muted: #94a3b8;
  --border: #2d3748;
  --msg-own: #4c1d95;
  --msg-other: #1e293b;
  --online: #22c55e;
  --danger: #ef4444;
  --radius: 12px;
  --sidebar-w: 260px;
  --online-w: 180px;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  background: var(--bg);
  color: var(--text);
  height: 100vh;
  overflow: hidden;
}

/* ── MODAL ── */
.modal-overlay {
  position: fixed; inset: 0;
  background: rgba(0,0,0,0.7);
  display: flex; align-items: center; justify-content: center;
  z-index: 1000;
  backdrop-filter: blur(4px);
}

.modal {
  background: var(--bg2);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 2rem;
  width: 360px;
  text-align: center;
  box-shadow: 0 20px 60px rgba(0,0,0,0.5);
}

.modal h2 { font-size: 1.5rem; margin-bottom: .5rem; }
.modal p { color: var(--text-muted); margin-bottom: 1.5rem; font-size: .9rem; }

.modal input {
  width: 100%;
  background: var(--bg3);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: .75rem 1rem;
  color: var(--text);
  font-size: 1rem;
  margin-bottom: 1rem;
  outline: none;
  transition: border-color .2s;
}

.modal input:focus { border-color: var(--accent2); }

.modal button {
  width: 100%;
  background: var(--accent);
  color: white;
  border: none;
  border-radius: 8px;
  padding: .75rem;
  font-size: 1rem;
  cursor: pointer;
  transition: background .2s;
  font-weight: 600;
}

.modal button:hover { background: var(--accent-hover); }

/* ── LAYOUT ── */
.hidden { display: none !important; }

#app {
  display: flex;
  height: 100vh;
}

/* ── SIDEBAR ── */
.sidebar {
  width: var(--sidebar-w);
  background: var(--bg2);
  border-right: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  flex-shrink: 0;
}

.sidebar-header {
  padding: 1.25rem 1rem;
  border-bottom: 1px solid var(--border);
}

.sidebar-header h1 {
