}

.sidebar-section {
  flex: 1;
  overflow-y: auto;
  padding: 1rem;
}

.section-title {
  font-size: .75rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: .08em;
  color: var(--text-muted);
