.chat-area {
  flex: 1;
  display: flex;
  overflow: hidden;
  position: relative;
}

.no-room {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  color: var(--text-muted);
  gap: 1rem;
}

.no-room-icon { font-size: 3rem; opacity: .4; }
.no-room p { font-size: 1rem; }

/* ── ROOM VIEW ── */
#room-view {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.chat-header {
  padding: 1rem 1.25rem;
  border-bottom: 1px solid var(--border);
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--bg2);
  flex-shrink: 0;
}

.room-title {
  font-size: 1.1rem;
  font-weight: 700;
}

.chat-header-right {
  display: flex;
  align-items: center;
  gap: .75rem;
}

.online-count {
  font-size: .8rem;
  color: var(--online);
  font-weight: 600;
}

.leave-btn {
  background: transparent;
  color: var(--danger);
  border: 1px solid var(--danger);
  border-radius: 6px;
  padding: .3rem .7rem;
  font-size: .8rem;
  cursor: pointer;
  transition: all .2s;
}

.leave-btn:hover {
  background: var(--danger);
  color: white;
}

/* ── CHAT BODY ── */
.chat-body {
  flex: 1;
  overflow-y: auto;
  padding: 1rem 1.25rem;
  display: flex;
  flex-direction: column;
  gap: .5rem;
  scroll-behavior: smooth;
}

.chat-body::-webkit-scrollbar { width: 6px; }
.chat-body::-webkit-scrollbar-track { background: transparent; }
.chat-body::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }

/* ── MESSAGES ── */
.messages { display: flex; flex-direction: column; gap: .5rem; }

.msg {
  display: flex;
  flex-direction: column;
  max-width: 70%;
}

.msg.own { align-self: flex-end; align-items: flex-end; }
.msg.other { align-self: flex-start; align-items: flex-start; }

.msg-meta {
  font-size: .7rem;
  color: var(--text-muted);
  margin-bottom: .2rem;
  padding: 0 .25rem;
}

.msg-bubble {
  padding: .6rem .9rem;
  border-radius: 16px;
  font-size: .9rem;
  line-height: 1.5;
  word-break: break-word;
  white-space: pre-wrap;
}

.msg.own .msg-bubble {
  background: var(--msg-own);
  border-bottom-right-radius: 4px;
  color: #e9d5ff;
}

.msg.other .msg-bubble {
  background: var(--msg-other);
  border-bottom-left-radius: 4px;
}

.msg-time {
  font-size: .65rem;
  color: var(--text-muted);
  margin-top: .15rem;
  padding: 0 .25rem;
}

/* System messages */
.msg-system {
  align-self: center;
  font-size: .75rem;
  color: var(--text-muted);
  background: rgba(255,255,255,.05);
  padding: .25rem .75rem;
  border-radius: 20px;
  margin: .25rem 0;
